import React from "react";
import { useState, createContext, useContext, useEffect,  } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  
  const [order, setOrder ] = useState({});
  const [menu ,setMenu] = useState([]);
  
  console.log("order in context:",order)
  const addToOrder = (ProductId) =>{
    if(!order[ProductId])
    {
      setOrder((prev) => ({...prev,[ProductId] : 1}));
    }
    else{
      setOrder((prev)=>(console));
    }
  }

  const removeItem =(ProductId) =>{
    setOrder((prev) => {
      const temp ={...prev};
      delete temp[ProductId];
      return temp;
    })
  }

  const removeFromOrder =(ProductId)=>{
    if(order[ProductId])
    {
      setOrder(prev => ({...prev,[ProductId] : prev[ProductId]-1}))
    }
  }

  return (
    <OrderContext.Provider value={{ order, addToOrder, menu, setMenu, removeFromOrder ,removeItem}}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext = () => useContext(OrderContext);
